Then wrap the body in src/app/layout.tsx with: import { Providers } from './providers'; and wrap {children} with Providers.

Create src/components/ConnectWallet.tsx with the following content:

```typescript
'use client';
import { useAccount, useConnect, useDisconnect } from 'wagmi';

export function ConnectWallet() {
  const { address, isConnected } = useAccount();
  const { connect, connectors } = useConnect();
  const { disconnect } = useDisconnect();

  if (isConnected) {
    return (
      <div>
        <p>Connected: {address}</p>
        <button onClick={() => disconnect()}>Disconnect</button>
      </div>
    );
  }

  return (
    <div>
      {connectors.map((connector) => (
        <button key={connector.id} onClick={() => connect({ connector })}>
          Connect {connector.name}
        </button>
      ))}
    </div>
  );
}
```

This renders a connect/disconnect button using the injected (MetaMask) connector.

Create src/components/BlockNumber.tsx with:

```typescript
'use client';
import { useBlockNumber } from 'wagmi';
import { polkadotHubTestnet } from '../wagmi';

export function BlockNumber() {
  const { data: blockNumber } = useBlockNumber({
    chainId: polkadotHubTestnet.id,
    watch: true,
  });
  return <p>Current block: {blockNumber?.toString() ?? 'Loading...'}</p>;
}
```

The watch: true option polls for new blocks and updates the component automatically.

Create `src/components/StorageRead.tsx` to read the current value from a Storage contract deployed on Polkadot Hub TestNet. This step uses the publicly-deployed Storage contract at `0xc01Ee7f10EA4aF4673cFff62710E1D7792aBa8f3` (originally deployed for the zero-to-hero dApp tutorial). Its ABI uses `store(uint256)` and `retrieve()`, which matches the inline ABI below. If you'd rather use your own contract, deploy via `deploy-basic-contract-hardhat` and replace the address; ensure the deployed contract exposes `retrieve()` (or update the ABI to match your contract's getter):

```typescript
'use client';
import { useReadContract } from 'wagmi';
import { polkadotHubTestnet } from '../wagmi';

const STORAGE_ABI = [
  {
    inputs: [],
    name: 'retrieve',
    outputs: [{ internalType: 'uint256', name: '', type: 'uint256' }],
    stateMutability: 'view',
    type: 'function',
  },
] as const;

const CONTRACT_ADDRESS = '0xc01Ee7f10EA4aF4673cFff62710E1D7792aBa8f3' as `0x${string}`;

export function StorageRead() {
  const { data, isLoading } = useReadContract({
    address: CONTRACT_ADDRESS,
    abi: STORAGE_ABI,
    functionName: 'retrieve',
    chainId: polkadotHubTestnet.id,
  });

  return (
    <p>Stored value: {isLoading ? 'Loading...' : data?.toString() ?? 'N/A'}</p>
  );
}
```

The `as \`0x${string}\`` cast satisfies viem/wagmi's strict address type — without it, the literal string would type-check as `string` and cause a build failure on the `useReadContract({ address: ... })` call.

Create `src/components/StorageWrite.tsx` to send a `store(uint256)` transaction to the same contract used in step 7:

```typescript
'use client';
import { useWriteContract, useAccount } from 'wagmi';
import { polkadotHubTestnet } from '../wagmi';
import { useState } from 'react';

const STORAGE_ABI = [
  {
    inputs: [{ internalType: 'uint256', name: 'num', type: 'uint256' }],
    name: 'store',
    outputs: [],
    stateMutability: 'nonpayable',
    type: 'function',
  },
] as const;

const CONTRACT_ADDRESS = '0xc01Ee7f10EA4aF4673cFff62710E1D7792aBa8f3' as `0x${string}`;

export function StorageWrite() {
  const { isConnected } = useAccount();
  const { writeContract, isPending, isSuccess } = useWriteContract();
  const [value, setValue] = useState('');

  const handleStore = () => {
    writeContract({
      address: CONTRACT_ADDRESS,
      abi: STORAGE_ABI,
      functionName: 'store',
      args: [BigInt(value)],
      chainId: polkadotHubTestnet.id,
    });
  };

  if (!isConnected) return <p>Connect your wallet to write.</p>;

  return (
    <div>
      <input value={value} onChange={e => setValue(e.target.value)} placeholder='Enter number' />
      <button onClick={handleStore} disabled={isPending}>
        {isPending ? 'Storing...' : 'Store'}
      </button>
      {isSuccess && <p>Transaction submitted!</p>}
    </div>
  );
}
```

Same address as step 6. This step requires a connected wallet (from step 3's `ConnectWallet`) and PAS tokens for the transaction fee — get tokens from <https://faucet.polkadot.io/>.

Open src/app/page.tsx and replace its content with:

```typescript
