Then run npm run dev to start the Next.js dev server on http://localhost:3000.

Create a file named `Storage.sol` with the following content:

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.9;

contract Storage {
    uint256 public storedNumber;

    function setNumber(uint256 _newNumber) public {
        storedNumber = _newNumber;
    }
}
```

This contract stores a number in `storedNumber` (publicly readable via auto-generated getter) and exposes `setNumber(uint256)` as the write function.

Delegate to the user: Open https://remix.ethereum.org in the browser. In the File Explorer panel (left sidebar), create a new file named `IERC20-precompile.sol`. Paste the following interface into the file:

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface IERC20 {
    function totalSupply() external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function allowance(address owner, address spender) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}
```

IMPORTANT: The optional ERC-20 metadata functions (`name()`, `symbol()`, `decimals()`) are NOT implemented in this precompile — do not add them to the interface or they will revert.

Click the Solidity Compiler tab (shield icon), set the compiler version to 0.8.20 (or higher), and click 'Compile IERC20-precompile.sol'.

Delegate to the user: Create a new file named `IStorage.sol` in Remix and paste the following interface (from the Polkadot SDK IStorage.sol at https://github.com/paritytech/polkadot-sdk/blob/62fa27df30d985600963fd5bcec1080e4c63fd4b/substrate/frame/revive/uapi/sol/IStorage.sol):

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

interface IStorage {
    // Read full value at key
    function get(bytes32 key) external view returns (bytes memory);
    // Read a range: offset bytes in, length bytes out
    function get_range(bytes32 key, uint32 offset, uint32 length) external view returns (bytes memory);
    // Read up to max_length bytes from the start
    function get_prefix(bytes32 key, uint32 max_length) external view returns (bytes memory);
    // Write value at key
    function set(bytes32 key, bytes memory value) external;
    // Delete value at key
    function remove(bytes32 key) external;
    // True if key exists (even if value is empty)
